#!/bin/bash
# HERCOSSNUX NPU - Fase A, Paso 2 (Layer 1): MAC, requantize (3 etapas) y maxpool.
# Requiere: ghdl 4.1.0 --std=08, python3. Requiere el Paso 1 ya instalado.
# Linea esperada al final:
# NPU PASO2 OK L1 4/4 PASS MUTACIONES 11/11 FAIL
(
set -e
DIR="$HOME/vhdl_repo/IP_Cores/NPU"
if [ ! -f "$DIR/model/npu_weights.hex" ]; then
  echo "FALLO: falta $DIR/model/npu_weights.hex (corre primero el Paso 1)"; exit 1
fi
mkdir -p "$DIR/rtl" "$DIR/tb" "$DIR/vec"
base64 -d << "EOF" > "$DIR/rtl/npu_pkg.vhd"

EOF
base64 -d << "EOF" > "$DIR/rtl/npu_mac.vhd"

EOF
base64 -d << "EOF" > "$DIR/rtl/npu_requant.vhd"

EOF
base64 -d << "EOF" > "$DIR/rtl/npu_pool.vhd"

EOF
base64 -d << "EOF" > "$DIR/tb/tb_npu_mac.vhd"

EOF
base64 -d << "EOF" > "$DIR/tb/tb_npu_requant.vhd"

EOF
base64 -d << "EOF" > "$DIR/tb/tb_npu_pool.vhd"

EOF
base64 -d << "EOF" > "$DIR/tb/tb_npu_latency.vhd"

EOF
base64 -d << "EOF" > "$DIR/gen_l1_vectors.py"

EOF
base64 -d << "EOF" > "$DIR/run_l1.sh"

EOF
chmod +x "$DIR/run_l1.sh"
cd "$DIR"
python3 gen_l1_vectors.py model/npu_weights.hex vec > /dev/null
bash run_l1.sh
)
